// Extract and format the launch data from the GraphQL response
const launches = [];
const response = $input.first().json;

// Check if we have valid data
if (!response || !response.data || !response.data.posts || !response.data.posts.edges) {
  return [{ json: { error: 'Invalid response from Product Hunt API' } }];
}

// Process each launch
response.data.posts.edges.forEach(edge => {
  const launch = edge.node;

  // Format makers data
  const makers = [];
  if (launch.makers && launch.makers.edges) {
    launch.makers.edges.forEach(makerEdge => {
      const maker = makerEdge.node;
      makers.push({
        id: maker.id,
        name: maker.name,
        username: maker.username,
        profileUrl: maker.profileUrl,
        twitterUsername: maker.twitterUsername
      });
    });
  }

  // Add formatted launch to our array
  launches.push({
    id: launch.id,
    name: launch.name,
    tagline: launch.tagline,
    description: launch.description,
    url: launch.url,
    createdAt: launch.createdAt,
    makers: makers
  });
});

return launches.map(launch => ({ json: launch }));

// Filter out launches that have already been processed
const newLaunches = [];
const processedLaunches = [];

// Get current launches
const currentLaunches = $input.first().json;

// Get processed launches if available
if ($input.last() && $input.last().json) {
  const processedData = $input.last().json;
  if (Array.isArray(processedData)) {
    processedLaunches.push(...processedData);
  }
}

// Get processed launch IDs for quick lookup
const processedIds = new Set(processedLaunches.map(launch => launch.id));

// Filter out already processed launches
if (Array.isArray(currentLaunches)) {
  currentLaunches.forEach(launch => {
    if (!processedIds.has(launch.id)) {
      newLaunches.push(launch);
    }
  });
} else {
  // If we have a single launch
  if (!processedIds.has(currentLaunches.id)) {
    newLaunches.push(currentLaunches);
  }
}

// Return the new launches
return newLaunches.map(launch => ({ json: launch }));

// Prepare data for email sending
const emailsToSend = [];

// Get the new launches
const newLaunches = $input.all().map(item => item.json);

// Process each launch and create email data for each maker
newLaunches.forEach(launch => {
  if (launch.makers && launch.makers.length > 0) {
    launch.makers.forEach(maker => {
      // Create personalized email data
      emailsToSend.push({
        to: maker.email || `${maker.username}@producthunt.com`, // Fallback if email not available
        subject: `Congratulations on launching ${launch.name} on Product Hunt!`,
        html: `
          <p>Hi ${maker.name},</p>
          <p>I noticed your recent launch <strong>${launch.name}</strong> on Product Hunt and wanted to reach out to congratulate you!</p>
          <p><em>${launch.tagline}</em></p>
          <p>${launch.description}</p>
          <p>I'm impressed by what you've built and would love to learn more about your journey. Would you be open to a brief chat sometime next week?</p>
          <p>Best regards,<br>Your Name</p>
        `,
        maker: maker,
        launch: launch
      });
    });
  }
});

return emailsToSend.map(email => ({ json: email }));

// Update the list of processed launches
const processedLaunches = [];

// Get previously processed launches if available
if ($input.first() && $input.first().json) {
  const processedData = $input.first().json;
  if (Array.isArray(processedData)) {
    processedLaunches.push(...processedData);
  }
}

// Get the newly processed launches
const newLaunches = $input.last().json;

// Add new launches to the processed list
if (Array.isArray(newLaunches)) {
  processedLaunches.push(...newLaunches);
} else {
  processedLaunches.push(newLaunches);
}

// Return the updated list
return [{ json: processedLaunches }];

// Log that no new launches were found
console.log('No new Product Hunt launches to process today.');

return [{ json: { message: 'No new launches found' } }];

// Handle errors in the flow
const error = $input.first().json;
console.error('Error in Product Hunt outreach flow:', error);

// Log the error for debugging
return [{ json: { error: error.message || 'Unknown error', timestamp: new Date().toISOString() } }];
